function LFightTest.TranslateFormation(formation)
	local formationData = {}
	formationData.formationType = LCombatTypeConst.COMBAT_TEST_BATTLE
	formationData.formationRefId = formation.formationRefId
	-- 【G公共支持】删除神器功能相关数据
	-- formationData.artifactId = formation.artifactId
	formationData.treasureSkilIds = formation.treasureSkilIds
	-- formationData.treasurePassiveSkill = formation.treasurePassiveSkill
	formationData.teamIndex = 1
	formationData.power = 0
	local gridA = {}
	formationData.grids = gridA
	formationData.divineWeaponStarRefIds = formation.divineWeaponStarRefIds or {}

	for k,v in pairs(formation.grids) do
		table.insert(gridA, {
			id = tostring(v.id),
			grid = v.grid
		})
	end
	-- 【C宠物系统】删掉宠物系统相关
